#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(string s) {
        unordered_map<char, int> val{{'I',1},{'V',5},{'X',10},{'L',50},{'C',100},{'D',500},{'M',1000}};
        int total = 0;
        for (size_t i = 0; i < s.size(); ++i) {
            if (i + 1 < s.size() && val[s[i]] < val[s[i+1]]) {
                total += val[s[i+1]] - val[s[i]];
                ++i; // skip next
            } else {
                total += val[s[i]];
            }
        }
        return total;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s;
    if(!(cin >> s)) return 0;
    Solution sol;
    int ans = sol.solve(s);
    cout << ans << "\n";
    return 0;
}
